// Parsea la respuesta de Anthropic y verifica duplicados
const response = $input.first().json;
const rawText = response.content[0].text;

const cleanText = rawText
  .replace(/^```json\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

try {
  const article = JSON.parse(cleanText);

  if (!article.slug || !article.title || !article.sections) {
    throw new Error('Faltan campos obligatorios: slug, title, o sections');
  }
  if (!Array.isArray(article.sections)) {
    throw new Error('sections debe ser un array');
  }
  if (article.sections.length < 10) {
    throw new Error(`Solo ${article.sections.length} secciones — mínimo requerido: 10`);
  }

  const today = new Date().toISOString().split('T')[0];
  article.date     = today;
  article.modified = today;
  article.source   = 'n8n_seo_diario';
  article.status   = 'published';

  // Verificar duplicados contra todos los posts existentes
  const topicsData   = $('Fetch Existing Topics').first().json;
  const existingPosts = topicsData.posts ?? [];
  const existingSlugs = existingPosts.map(p => p.slug);
  const existingTopicsList = existingPosts
    .map(p => `  • slug: "${p.slug}" | tema: "${p.title}"`)
    .join('\n');

  const isDuplicate = existingSlugs.includes(article.slug);

  // Devuelve wrapper: article limpio + meta para el IF node
  return [{
    json: {
      article,  // listo para insertar en Supabase
      meta: {
        isDuplicate,
        duplicateSlug:   article.slug,
        existingTopics:  existingTopicsList,
      }
    }
  }];
} catch (error) {
  throw new Error(`Error parseando JSON del artículo: ${error.message}\n\nTexto recibido: ${cleanText.substring(0, 500)}`);
}

// Extrae el artículo limpio del wrapper para insertarlo en Supabase
const data = $input.first().json;
return [{ json: data.article }];

// Construye el request de reintento indicando el slug duplicado
